let animTime=0,animRunning=true,animId=null;
let lastTimestamp=null;

function animate(ts){
  if(!animRunning)return;
  if(lastTimestamp===null)lastTimestamp=ts;
  const dt=(ts-lastTimestamp)/1000;
  lastTimestamp=ts;
  animTime+=dt*0.15; // speed
  renderCoin(animTime);
  animId=requestAnimationFrame(animate);
}

function startAnim(){
  animRunning=true;lastTimestamp=null;
  animId=requestAnimationFrame(animate);
}

window.demo={
  canvas:heroCanvas,
  setTime:function(t){
    renderCoin(t);
  },
  pause:function(){
    animRunning=false;
    if(animId)cancelAnimationFrame(animId);
  }
};

startAnim();

/* ===== EDITION COINS (2D Canvas) ===== */
const editionColors={
  bronze:{base:'#8B6914',light:'#c9a84c',dark:'#5a4510',spec:'#ffe8a0'},
  silver:{base:'#8a8a9a',light:'#d0d0e0',dark:'#4a4a5a',spec:'#ffffff'},
  gold:{base:'#c9a84c',light:'#f0d878',dark:'#8a6d2b',spec:'#fff8d0'},
  black:{base:'#1a1a22',light:'#3a3a4a',dark:'#0a0a10',spec:'#666680'}
};

function drawEditionCoin(canvas,edition){
  const ctx=canvas.getContext('2d');
  const w=canvas.width,h=canvas.height;
  const cx=w/2,cy=h/2,r=w*0.42;
  const col=editionColors[edition];

  ctx.clearRect(0,0,w,h);

  // Shadow
  ctx.save();
  ctx.beginPath();ctx.arc(cx+3,cy+4,r,0,Math.PI*2);
  ctx.fillStyle='rgba(0,0,0,0.4)';ctx.fill();
  ctx.restore();

  // Coin body with metallic gradient
  const grad=ctx.createRadialGradient(cx-r*0.3,cy-r*0.3,0,cx,cy,r);
  grad.addColorStop(0,col.light);
  grad.addColorStop(0.5,col.base);
  grad.addColorStop(1,col.dark);
  ctx.beginPath();ctx.arc(cx,cy,r,0,Math.PI*2);
  ctx.fillStyle=grad;ctx.fill();

  // Reeded edge
  ctx.save();ctx.beginPath();ctx.arc(cx,cy,r,0,Math.PI*2);ctx.clip();
  for(let i=0;i<48;i++){
    const a=(i/48)*Math.PI*2;
    const r1=r-2,r2=r-1;
    ctx.beginPath();
    ctx.moveTo(cx+Math.cos(a)*r1,cy+Math.sin(a)*r1);
    ctx.lineTo(cx+Math.cos(a)*r2,cy+Math.sin(a)*r2);
    ctx.strokeStyle=i%2===0?col.light:col.dark;
    ctx.lineWidth=1.5;ctx.stroke();
  }
  ctx.restore();

  // Inner ring
  ctx.beginPath();ctx.arc(cx,cy,r*0.88,0,Math.PI*2);
  ctx.strokeStyle=col.light;ctx.lineWidth=1.5;ctx.stroke();
  ctx.beginPath();ctx.arc(cx,cy,r*0.84,0,Math.PI*2);
  ctx.strokeStyle=col.dark;ctx.lineWidth=1;ctx.stroke();

  // Emblem or text based on edition
  ctx.save();ctx.translate(cx,cy);
  if(edition==='gold'||edition==='bronze'){
    // Shield emblem
    ctx.beginPath();
    ctx.moveTo(-r*0.25,-r*0.30);
    ctx.lineTo(r*0.25,-r*0.30);
    ctx.lineTo(r*0.30,-r*0.08);
    ctx.quadraticCurveTo(r*0.30,r*0.20,0,r*0.35);
    ctx.quadraticCurveTo(-r*0.30,r*0.20,-r*0.30,-r*0.08);
    ctx.closePath();
    ctx.fillStyle=col.light;ctx.fill();
    ctx.strokeStyle=col.dark;ctx.lineWidth=1.5;ctx.stroke();
    // Inner detail
    ctx.beginPath();
    ctx.moveTo(-r*0.16,-r*0.20);
    ctx.lineTo(r*0.16,-r*0.20);
    ctx.lineTo(r*0.20,-r*0.02);
    ctx.quadraticCurveTo(r*0.20,r*0.12,0,r*0.24);
    ctx.quadraticCurveTo(-r*0.20,r*0.12,-r*0.20,-r*0.02);
    ctx.closePath();
    ctx.fillStyle=col.dark;ctx.fill();
    // Star
    ctx.fillStyle=col.light;
    ctx.beginPath();
    for(let i=0;i<5;i++){
      const a=(i*72-90)*Math.PI/180;
      ctx.lineTo(Math.cos(a)*r*0.08,Math.sin(a)*r*0.08);
      const a2=((i*72+36)-90)*Math.PI/180;
      ctx.lineTo(Math.cos(a2)*r*0.035,Math.sin(a2)*r*0.035);
    }
    ctx.closePath();ctx.fill();
  }else if(edition==='silver'){
    ctx.font=`bold ${r*0.22}px Georgia`;ctx.fillStyle=col.light;ctx.textAlign='center';ctx.textBaseline='middle';
    ctx.fillText('10,000',0,-r*0.08);
    ctx.font=`bold ${r*0.10}px Georgia`;ctx.fillStyle=col.base;
    ctx.fillText('TOKENS',0,r*0.08);
    ctx.font=`${r*0.05}px Georgia`;ctx.fillStyle=col.dark;
    ctx.fillText('WTM',0,r*0.22);
  }else{
    // Black obsidian - mysterious design
    ctx.beginPath();
    for(let i=0;i<8;i++){
      const a=(i*45)*Math.PI/180;
      const rr=i%2===0?r*0.28:r*0.18;
      ctx.lineTo(Math.cos(a)*rr,Math.sin(a)*rr);
    }
    ctx.closePath();
    ctx.fillStyle=col.light;ctx.fill();
    ctx.strokeStyle=col.dark;ctx.lineWidth=1;ctx.stroke();
    ctx.font=`${r*0.06}px Georgia`;ctx.fillStyle=col.light;ctx.textAlign='center';ctx.textBaseline='middle';
    ctx.fillText('OBSIDIAN',0,r*0.25);
  }
  ctx.restore();

  // Specular highlight
  const specGrad=ctx.createRadialGradient(cx-r*0.35,cy-r*0.35,0,cx-r*0.35,cy-r*0.35,r*0.6);
  specGrad.addColorStop(0,'rgba(255,255,255,0.35)');
  specGrad.addColorStop(0.5,'rgba(255,255,255,0.08)');
  specGrad.addColorStop(1,'rgba(255,255,255,0)');
  ctx.beginPath();ctx.arc(cx,cy,r,0,Math.PI*2);
  ctx.fillStyle=specGrad;ctx.fill();

  // Edge highlight
  ctx.beginPath();ctx.arc(cx,cy,r,0,Math.PI*2);
  ctx.strokeStyle=col.light;ctx.lineWidth=2;ctx.stroke();

  // Sold out overlay
  if(edition==='gold'){
    ctx.save();
    ctx.globalAlpha=0.5;
    ctx.beginPath();ctx.arc(cx,cy,r,0,Math.PI*2);
    ctx.fillStyle='#000';ctx.fill();
    ctx.globalAlpha=1;
    ctx.font=`bold ${r*0.18}px Georgia`;ctx.fillStyle='#d45a5a';ctx.textAlign='center';ctx.textBaseline='middle';
    ctx.fillText('SOLD',0,-r*0.06);
    ctx.fillText('OUT',0,r*0.08);
    ctx.restore();
  }

  // Coming soon overlay
  if(edition==='black'){
    ctx.save();
    ctx.globalAlpha=0.4;
    ctx.beginPath();ctx.arc(cx,cy,r,0,Math.PI*2);
    ctx.fillStyle='#000';ctx.fill();
    ctx.globalAlpha=1;
    ctx.font=`bold ${r*0.12}px Georgia`;ctx.fillStyle='#7a9ec4';ctx.textAlign='center';ctx.textBaseline='middle';
    ctx.fillText('COMING',0,-r*0.06);
    ctx.fillText('SOON',0,r*0.08);
    ctx.restore();
  }
}

document.querySelectorAll('.edition-canvas').forEach(function(canvas){
  const edition=canvas.closest('.edition').dataset.edition;
  drawEditionCoin(canvas,edition);
});

})();
</script>
